// ServerInterface represents all server handlers.
type ServerInterface interface {
	// List devices in the current account (the Fleet)
	// (GET /api/v1/auth/devices)
	ListDevices(w http.ResponseWriter, r *http.Request)
	// Register a device for a profile and issue a device token
	// (POST /api/v1/auth/devices)
	RegisterDevice(w http.ResponseWriter, r *http.Request)
	// Revoke a device token ("retire from the Fleet")
	// (DELETE /api/v1/auth/devices/{deviceId})
	RevokeDevice(w http.ResponseWriter, r *http.Request, deviceId openapi_types.UUID)
	// Rename a device in the Fleet
	// (PATCH /api/v1/auth/devices/{deviceId})
	RenameDevice(w http.ResponseWriter, r *http.Request, deviceId openapi_types.UUID)
	// Authenticate an account and list its profiles
	// (POST /api/v1/auth/login)
	Login(w http.ResponseWriter, r *http.Request)
	// Resolve the current (account, profile, device) from the token
	// (GET /api/v1/auth/me)
	GetCurrentSession(w http.ResponseWriter, r *http.Request)
	// SSE stream of the current user's live play-state events (Beacon)
	// (GET /api/v1/beacon)
	BeaconStream(w http.ResponseWriter, r *http.Request, params BeaconStreamParams)
	// Continue-watching / on-deck items for the current profile
	// (GET /api/v1/continue)
	ListContinue(w http.ResponseWriter, r *http.Request)
	// Most common facets (genres + tags) across the account's manifest
	// (GET /api/v1/facets)
	ListFacets(w http.ResponseWriter, r *http.Request, params ListFacetsParams)
	// Media item detail with effective metadata
	// (GET /api/v1/items/{itemId})
	GetMediaItem(w http.ResponseWriter, r *http.Request, itemId openapi_types.UUID)
	// Direct-play capability decision for the item
	// (GET /api/v1/items/{itemId}/playback)
	GetPlaybackInfo(w http.ResponseWriter, r *http.Request, itemId openapi_types.UUID)
	// Current play-state (resume position) for the item
	// (GET /api/v1/items/{itemId}/progress)
	GetProgress(w http.ResponseWriter, r *http.Request, itemId openapi_types.UUID)
	// Heartbeat — upsert the resume position for the current profile
	// (PUT /api/v1/items/{itemId}/progress)
	ReportProgress(w http.ResponseWriter, r *http.Request, itemId openapi_types.UUID)
	// Direct-play media stream with HTTP range support
	// (GET /api/v1/items/{itemId}/stream)
	StreamItem(w http.ResponseWriter, r *http.Request, itemId openapi_types.UUID, params StreamItemParams)
	// Available subtitle tracks for an item
	// (GET /api/v1/items/{itemId}/subtitles)
	ListSubtitles(w http.ResponseWriter, r *http.Request, itemId openapi_types.UUID)
	// A subtitle track as WebVTT
	// (GET /api/v1/items/{itemId}/subtitles/{trackId})
	GetSubtitle(w http.ResponseWriter, r *http.Request, itemId openapi_types.UUID, trackId string, params GetSubtitleParams)
	// Start (or join) an HLS transcode session for an item
	// (POST /api/v1/items/{itemId}/transcode)
	StartTranscode(w http.ResponseWriter, r *http.Request, itemId openapi_types.UUID)
	// Mark an item watched / unwatched for the current profile
	// (POST /api/v1/items/{itemId}/watched)
	SetWatched(w http.ResponseWriter, r *http.Request, itemId openapi_types.UUID)
	// List the account's libraries
	// (GET /api/v1/libraries)
	ListLibraries(w http.ResponseWriter, r *http.Request)
	// Register a new media library (admin only)
	// (POST /api/v1/libraries)
	CreateLibrary(w http.ResponseWriter, r *http.Request)
	// Remove a library and its items (admin only)
	// (DELETE /api/v1/libraries/{libraryId})
	DeleteLibrary(w http.ResponseWriter, r *http.Request, libraryId openapi_types.UUID)
	// Browse movies in a library
	// (GET /api/v1/libraries/{libraryId}/movies)
	ListMovies(w http.ResponseWriter, r *http.Request, libraryId openapi_types.UUID, params ListMoviesParams)
	// Browse series in a library
	// (GET /api/v1/libraries/{libraryId}/series)
	ListSeries(w http.ResponseWriter, r *http.Request, libraryId openapi_types.UUID, params ListSeriesParams)
	// On-deck (up-next) episodes for series the user is currently watching
	// (GET /api/v1/ondeck)
	ListOnDeck(w http.ResponseWriter, r *http.Request, params ListOnDeckParams)
	// Service identity and version
	// (GET /api/v1/ping)
	Ping(w http.ResponseWriter, r *http.Request)
	// Get the calling device's playback preferences
	// (GET /api/v1/preferences)
	GetDevicePreferences(w http.ResponseWriter, r *http.Request)
	// Update the calling device's playback preferences
	// (PUT /api/v1/preferences)
	SetDevicePreferences(w http.ResponseWriter, r *http.Request)
	// Recently-added items (films + series) across the account
	// (GET /api/v1/recent)
	ListRecent(w http.ResponseWriter, r *http.Request, params ListRecentParams)
	// Trigger an immediate library re-scan ("rebuild the Manifest")
	// (POST /api/v1/scan)
	TriggerScan(w http.ResponseWriter, r *http.Request)
	// Current/last scan sweep status
	// (GET /api/v1/scan/status)
	GetScanStatus(w http.ResponseWriter, r *http.Request)
	// Full-text search across the account's films and series
	// (GET /api/v1/search)
	Search(w http.ResponseWriter, r *http.Request, params SearchParams)
	// Series detail with seasons and episodes
	// (GET /api/v1/series/{seriesId})
	GetSeries(w http.ResponseWriter, r *http.Request, seriesId openapi_types.UUID)
	// Live playback sessions (who's watching what, where, now)
	// (GET /api/v1/sessions)
	ListPlaybackSessions(w http.ResponseWriter, r *http.Request)
	// Transcode cache usage (Ballast)
	// (GET /api/v1/transcode/cache)
	GetTranscodeCache(w http.ResponseWriter, r *http.Request)
	// Encoders available on this host and the selected one
	// (GET /api/v1/transcode/capabilities)
	GetTranscodeCapabilities(w http.ResponseWriter, r *http.Request)
	// Live transcode sessions for the current account (The Helm)
	// (GET /api/v1/transcode/sessions)
	ListTranscodeSessions(w http.ResponseWriter, r *http.Request)
	// Stop a transcode session and purge its output
	// (DELETE /api/v1/transcode/{sessionId})
	StopTranscode(w http.ResponseWriter, r *http.Request, sessionId string)
	// HLS artifact for a session (master/variant playlist, init, or segment)
	// (GET /api/v1/transcode/{sessionId}/{file})
	GetTranscodeFile(w http.ResponseWriter, r *http.Request, sessionId string, file string)
	// List vaults visible to the current profile (own + shared)
	// (GET /api/v1/vaults)
	ListVaults(w http.ResponseWriter, r *http.Request)
	// Create a vault
	// (POST /api/v1/vaults)
	CreateVault(w http.ResponseWriter, r *http.Request)
	// Delete a vault (owner or admin)
	// (DELETE /api/v1/vaults/{vaultId})
	DeleteVault(w http.ResponseWriter, r *http.Request, vaultId openapi_types.UUID)
	// Vault detail with its items
	// (GET /api/v1/vaults/{vaultId})
	GetVault(w http.ResponseWriter, r *http.Request, vaultId openapi_types.UUID)
	// Rename / re-describe / toggle sharing (owner or admin)
	// (PATCH /api/v1/vaults/{vaultId})
	UpdateVault(w http.ResponseWriter, r *http.Request, vaultId openapi_types.UUID)
	// Add a film or series to a vault
	// (POST /api/v1/vaults/{vaultId}/items)
	AddVaultItem(w http.ResponseWriter, r *http.Request, vaultId openapi_types.UUID)
	// Remove an item from a vault
	// (DELETE /api/v1/vaults/{vaultId}/items/{entryId})
	RemoveVaultItem(w http.ResponseWriter, r *http.Request, vaultId openapi_types.UUID, entryId openapi_types.UUID)
	// Reorder a vault's items
	// (PUT /api/v1/vaults/{vaultId}/order)
	ReorderVault(w http.ResponseWriter, r *http.Request, vaultId openapi_types.UUID)
	// Liveness/readiness probe
	// (GET /healthz)
	GetHealth(w http.ResponseWriter, r *http.Request)
}

